SELECT count(*) FROM title, kind_type, movie_info, movie_keyword, info_type, movie_companies, cast_info, role_type, name WHERE title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_info.info_type_id = info_type.id AND movie_companies.movie_id = title.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND cast_info.person_id = name.id;